21	struct Chunk {
22	  Table* table = nullptr;
23	  Code code;
24	  const table::Entry* entries = nullptr;
25	  size_t size = 0;
26	  size_t cursor = 0;
27	  string remaining_code;  // for predictive queries
28	  size_t matching_code_size = 0;
29	  double credibility = 0.0;
30	  double quality_len = 0.0;
31	
32	  Chunk() = default;
33	  Chunk(Table* t,
34	        const Code& c,
35	        const table::Entry* e,
36	        size_t m,
37	        double cr = 0.0,
38	        double q = 0.0)
39	      : table(t),
40	        code(c),
41	        entries(e),
42	        size(1),
43	        cursor(0),
44	        matching_code_size(m),
45	        credibility(cr),
46	        quality_len(q) {}
47	  Chunk(Table* t, const TableAccessor& a, double cr = 0.0, double q = 0.0)
48	      : Chunk(t, a, string(), cr, q) {}
49	  Chunk(Table* t,
50	        const TableAccessor& a,
51	        const string& r,
52	        double cr = 0.0,
53	        double q = 0.0)
54	      : table(t),
55	        code(a.index_code()),
56	        entries(a.entry()),
57	        size(a.remaining()),
58	        cursor(0),
59	        remaining_code(r),
60	        matching_code_size(a.index_code().size()),
61	        credibility(cr),
62	        quality_len(q) {}
63	
64	  bool is_exact_match() const { return matching_code_size == code.size(); }
65	
66	  bool is_predictive_match() const { return matching_code_size < code.size(); }
67	};
68	
69	struct QueryResult {
70	  vector<Chunk> chunks;
71	};
72	
73	bool compare_chunk_by_head_element(const Chunk& a, const Chunk& b) {
74	  if (!a.entries || a.cursor >= a.size)
75	    return false;
76	  if (!b.entries || b.cursor >= b.size)
77	    return true;
78	  if (a.is_exact_match() != b.is_exact_match())
79	    return a.is_exact_match() > b.is_exact_match();
80	  if (a.remaining_code.length() != b.remaining_code.length())
81	    return a.remaining_code.length() < b.remaining_code.length();
82	  return a.credibility + a.entries[a.cursor].weight >
83	         b.credibility + b.entries[b.cursor].weight;  // by weight desc
84	}
85	
86	struct CodeMatch {
87	  bool success;
88	  size_t depth;
89	  size_t end_pos;
90	};
91	
92	CodeMatch match_extra_code(const table::Code* extra_code,
93	                           size_t depth,
94	                           const SyllableGraph& syll_graph,
95	                           size_t current_pos,
96	                           bool predict_word) {
97	  const CodeMatch kFailed{false, 0, 0};
98	  if (!extra_code || depth >= extra_code->size)
99	    return {true, depth, current_pos};
100	  if (current_pos >= syll_graph.interpreted_length) {
101	    if (predict_word)
102	      return {true, depth, syll_graph.interpreted_length};
103	    else
104	      return kFailed;
105	  }
106	  auto index = syll_graph.indices.find(current_pos);
107	  if (index == syll_graph.indices.end())
108	    return kFailed;
109	  SyllableId current_syll_id = extra_code->at[depth];
110	  auto spellings = index->second.find(current_syll_id);
111	  if (spellings == index->second.end())
112	    return kFailed;
113	  CodeMatch best_match = kFailed;
114	  for (const SpellingProperties* props : spellings->second) {
115	    CodeMatch match = match_extra_code(extra_code, depth + 1, syll_graph,
116	                                       props->end_pos, predict_word);
117	    if (!match.success)
118	      continue;
119	    if (match.end_pos > best_match.end_pos)
120	      best_match = match;
121	  }
122	  return best_match;
123	}
