238	static void lookup_table(Table* table,
239	                         DictEntryCollector* collector,
240	                         const SyllableGraph& syllable_graph,
241	                         size_t start_pos,
242	                         bool predict_word,
243	                         double initial_credibility) {
244	  TableQueryResult result;
245	  if (!table->Query(syllable_graph, start_pos, &result)) {
246	    return;
247	  }
248	  // copy result
249	  for (auto& v : result) {
250	    size_t end_pos = v.first;
251	    for (TableAccessor& a : v.second) {
252	      double cr = initial_credibility + a.credibility();
253	      double q = a.quality_len();
254	      if (a.extra_code()) {
255	        do {
256	          dictionary::CodeMatch match = dictionary::match_extra_code(
257	              a.extra_code(), 0, syllable_graph, end_pos, predict_word);
258	          if (!match.success)
259	            continue;
260	          size_t matching_code_size = a.index_code().size() + match.depth;
261	          (*collector)[match.end_pos].AddChunk(
262	              {table, a.code(), a.entry(), matching_code_size, cr, q});
263	        } while (a.Next());
264	      } else {
265	        (*collector)[end_pos].AddChunk({table, a, cr, q});
266	      }
267	    }
268	  }
269	}
