351	bool Dictionary::Decode(const Code& code, vector<string>* result) {
352	  if (!result || tables_.empty())
353	    return false;
354	  result->clear();
355	  for (SyllableId c : code) {
356	    string s = primary_table()->GetSyllableById(c);
357	    if (s.empty())
358	      return false;
359	    result->push_back(s);
360	  }
361	  return true;
362	}
