425	Dictionary* DictionaryComponent::Create(const Ticket& ticket) {
426	  if (!ticket.schema)
427	    return nullptr;
428	  Config* config = ticket.schema->config();
429	  string dict_name;
430	  if (!config->GetString(ticket.name_space + "/dictionary", &dict_name)) {
431	    LOG(ERROR) << ticket.name_space << "/dictionary not specified in schema '"
432	               << ticket.schema->schema_id() << "'.";
433	    return nullptr;
434	  }
435	  if (dict_name.empty()) {
436	    return nullptr;  // not requiring static dictionary
437	  }
438	  string prism_name;
439	  if (!config->GetString(ticket.name_space + "/prism", &prism_name)) {
440	    prism_name = dict_name;
441	  }
442	  vector<string> packs;
443	  if (auto pack_list = config->GetList(ticket.name_space + "/packs")) {
444	    for (const auto& item : *pack_list) {
445	      if (auto value = As<ConfigValue>(item)) {
446	        packs.push_back(value->str());
447	      }
448	    }
449	  }
450	  return Create(std::move(dict_name), std::move(prism_name), std::move(packs));
451	}
452	
453	Dictionary* DictionaryComponent::Create(string dict_name,
454	                                        string prism_name,
455	                                        vector<string> packs) {
456	  // obtain prism and primary table objects
457	  auto primary_table = table_map_[dict_name].lock();
458	  if (!primary_table) {
459	    auto file_path = table_resource_resolver_->ResolvePath(dict_name);
460	    table_map_[dict_name] = primary_table = New<Table>(file_path);
461	  }
462	  auto prism = prism_map_[prism_name].lock();
463	  if (!prism) {
464	    auto file_path = prism_resource_resolver_->ResolvePath(prism_name);
465	    prism_map_[prism_name] = prism = New<Prism>(file_path);
466	  }
467	  vector<of<Table>> tables = {std::move(primary_table)};
468	  for (const auto& pack : packs) {
469	    auto table = table_map_[pack].lock();
470	    if (!table) {
471	      auto file_path = table_resource_resolver_->ResolvePath(pack);
472	      table_map_[pack] = table = New<Table>(file_path);
473	    }
474	    tables.push_back(std::move(table));
475	  }
476	  return new Dictionary(std::move(dict_name), std::move(packs),
477	                        std::move(tables), std::move(prism));
478	}
