296	bool DictCompiler::BuildPrism(const path& schema_file,
297	                              uint32_t dict_file_checksum,
298	                              uint32_t schema_file_checksum) {
299	  LOG(INFO) << "building prism...";
300	  auto target_path =
301	      relocate_target(prism_->file_path(), target_resolver_.get());
302	  prism_ = New<Prism>(target_path);
303	
304	  // get syllabary from primary table, which may not be rebuilt
305	  Syllabary syllabary;
306	  const auto& primary_table = tables_[0];
307	  if (!primary_table->Load() || !primary_table->GetSyllabary(&syllabary) ||
308	      syllabary.empty())
309	    return false;
310	  // apply spelling algebra and prepare corrections (if enabled)
311	  Script script;
312	  if (!schema_file.empty()) {
313	    Config config;
314	    if (!config.LoadFromFile(schema_file)) {
315	      LOG(ERROR) << "error loading prism definition from " << schema_file;
316	      return false;
317	    }
318	    Projection p;
319	    auto algebra = config.GetList("speller/algebra");
320	    if (algebra && p.Load(algebra)) {
321	      for (const auto& x : syllabary) {
322	        script.AddSyllable(x);
323	      }
324	      if (!p.Apply(&script)) {
325	        script.clear();
326	      }
327	    }
328	
329	#if 0
330	    // build corrector
331	    bool enable_correction = false; // Avoid if initializer to comfort compilers
332	    if (config.GetBool("translator/enable_correction", &enable_correction) &&
333	        enable_correction) {
334	      path corrector_path(prism_->file_path());
335	      corrector_path.replace_extension("");
336	      corrector_path.replace_extension(".correction.bin");
337	      auto target_path = relocate_target(corrector_path,
338	                                         target_resolver_.get());
339	      correction_ = New<EditDistanceCorrector>(target_path);
340	      if (correction_->Exists()) {
341	        correction_->Remove();
342	      }
343	      if (!correction_->Build(syllabary, &script,
344	                         dict_file_checksum, schema_file_checksum) ||
345	          !correction_->Save()) {
346	        return false;
347	      }
348	    }
349	#endif
350	  }
351	  if ((options_ & kDump) && !script.empty()) {
352	    path dump_path(prism_->file_path());
353	    dump_path.replace_extension(".txt");
354	    script.Dump(dump_path);
355	  }
356	  // build .prism.bin
357	  {
358	    prism_->Remove();
359	    if (!prism_->Build(syllabary, script.empty() ? nullptr : &script,
360	                       dict_file_checksum, schema_file_checksum) ||
361	        !prism_->Save()) {
362	      return false;
363	    }
364	  }
365	
366	  return true;
367	}
