23	    leveldb::ReadOptions options;
24	    options.fill_cache = false;
25	    iterator = db->NewIterator(options);
26	  }
27	
28	  bool IsValid() const { return iterator && iterator->Valid(); }
29	
30	  string GetKey() const { return iterator->key().ToString(); }
31	
32	  string GetValue() const { return iterator->value().ToString(); }
33	
34	  void Next() { iterator->Next(); }
35	
36	  bool Jump(const string& key) {
37	    if (!iterator) {
38	      return false;
39	    }
40	    iterator->Seek(key);
41	    return true;
42	  }
43	
44	  void Release() {
45	    delete iterator;
46	    iterator = nullptr;
47	  }
48	};
