66	
67	  bool Fetch(const string& key, string* value) {
68	    auto status = ptr->Get(leveldb::ReadOptions(), key, value);
69	    return status.ok();
70	  }
71	
72	  bool Update(const string& key, const string& value, bool write_batch) {
73	    if (write_batch) {
74	      batch.Put(key, value);
75	      return true;
76	    }
77	    auto status = ptr->Put(leveldb::WriteOptions(), key, value);
78	    return status.ok();
79	  }
80	
81	  bool Erase(const string& key, bool write_batch) {
82	    if (write_batch) {
83	      batch.Delete(key);
84	      return true;
85	    }
86	    auto status = ptr->Delete(leveldb::WriteOptions(), key);
87	    return status.ok();
88	  }
89	
90	  void ClearBatch() { batch.Clear(); }
91	
92	  bool CommitBatch() {
93	    auto status = ptr->Write(leveldb::WriteOptions(), &batch);
94	    return status.ok();
95	  }
96	};
