123	    return false;
124	  *key = cursor_->GetKey();
125	  if (!MatchesPrefix(*key)) {
126	    return false;
127	  }
128	  if (is_metadata_query_) {
129	    key->erase(0, 1);  // remove meta character
130	  }
131	  *value = cursor_->GetValue();
