81	
82	bool Prism::Load() {
83	  LOG(INFO) << "loading prism file: " << file_path();
84	
85	  if (IsOpen())
86	    Close();
87	
88	  if (!OpenReadOnly()) {
89	    LOG(ERROR) << "error opening prism file '" << file_path() << "'.";
90	    return false;
91	  }
92	
93	  metadata_ = Find<prism::Metadata>(0);
94	  if (!metadata_) {
95	    LOG(ERROR) << "metadata not found.";
96	    Close();
97	    return false;
98	  }
99	  if (strncmp(metadata_->format, kPrismFormatPrefix, kPrismFormatPrefixLen)) {
100	    LOG(ERROR) << "invalid metadata.";
101	    Close();
102	    return false;
103	  }
104	  format_ = atof(&metadata_->format[kPrismFormatPrefixLen]);
105	
106	  // 版本檢查: 強制重構舊版本
107	  if (format_ < kPrismFormatVersion - DBL_EPSILON) {
108	    LOG(INFO) << "prism format " << format_ << " is too old. upgrading to "
109	              << kPrismFormatVersion;
110	    Close();
111	    return false;
112	  }
113	
114	  char* array = metadata_->double_array.get();
115	  if (!array) {
116	    LOG(ERROR) << "double array image not found.";
117	    Close();
118	    return false;
119	  }
120	  size_t array_size = metadata_->double_array_size;
121	  LOG(INFO) << "found double array image of size " << array_size << ".";
122	  trie_->set_array(array, array_size);
123	
124	  spelling_map_ = NULL;
125	  if (format_ > 1.0 - DBL_EPSILON) {
126	    spelling_map_ = metadata_->spelling_map.get();
127	  }
128	  return true;
129	}
