139	bool Prism::Build(const Syllabary& syllabary,
140	                  const Script* script,
141	                  uint32_t dict_file_checksum,
142	                  uint32_t schema_file_checksum) {
143	  // building double-array trie
144	  size_t num_syllables = syllabary.size();
145	  size_t num_spellings = script ? script->size() : syllabary.size();
146	  vector<const char*> keys(num_spellings);
147	  size_t key_id = 0;
148	  size_t map_size = 0;
149	  if (script) {
150	    for (auto it = script->begin(); it != script->end(); ++it, ++key_id) {
151	      keys[key_id] = it->first.c_str();
152	      map_size += it->second.size();
153	    }
154	  } else {
155	    for (auto it = syllabary.begin(); it != syllabary.end(); ++it, ++key_id) {
156	      keys[key_id] = it->c_str();
157	    }
158	  }
159	  if (0 != trie_->build(num_spellings, &keys[0])) {
160	    LOG(ERROR) << "Error building double-array trie.";
161	    return false;
162	  }
163	  // creating prism file
164	  size_t array_size = trie_->size();
165	  size_t image_size = trie_->total_size();
166	  const size_t kDescriptorExtraSize = 12;
167	  size_t estimated_map_size =
168	      num_spellings * 12 +
169	      map_size * (4 + sizeof(prism::SpellingDescriptor) + kDescriptorExtraSize);
170	  const size_t kReservedSize = 1024;
171	  if (!Create(image_size + estimated_map_size + kReservedSize)) {
172	    LOG(ERROR) << "Error creating prism file '" << file_path() << "'.";
173	    return false;
174	  }
175	  // creating metadata
176	  auto metadata = Allocate<prism::Metadata>();
177	  if (!metadata) {
178	    LOG(ERROR) << "Error creating metadata in file '" << file_path() << "'.";
179	    return false;
180	  }
181	  metadata->dict_file_checksum = dict_file_checksum;
182	  metadata->schema_file_checksum = schema_file_checksum;
183	  metadata->num_syllables = num_syllables;
184	  metadata->num_spellings = num_spellings;
185	  metadata_ = metadata;
186	  // alphabet
187	  {
188	    set<char> alphabet;
189	    for (size_t i = 0; i < num_spellings; ++i)
190	      for (const char* p = keys[i]; *p; ++p)
191	        alphabet.insert(*p);
192	    char* p = metadata->alphabet;
193	    set<char>::const_iterator c = alphabet.begin();
194	    for (; c != alphabet.end(); ++p, ++c)
195	      *p = *c;
196	    *p = '\0';
197	  }
198	  // saving double-array image
199	  char* array = Allocate<char>(image_size);
200	  if (!array) {
201	    LOG(ERROR) << "Error creating double-array image.";
202	    return false;
203	  }
204	  std::memcpy(array, trie_->array(), image_size);
205	  metadata->double_array = array;
206	  metadata->double_array_size = array_size;
207	  // building spelling map
208	  if (script) {
209	    map<string, SyllableId> syllable_to_id;
210	    SyllableId syll_id = 0;
211	    for (auto it = syllabary.begin(); it != syllabary.end(); ++it) {
212	      syllable_to_id[*it] = syll_id++;
213	    }
214	    auto spelling_map = CreateArray<prism::SpellingMapItem>(num_spellings);
215	    if (!spelling_map) {
216	      LOG(ERROR) << "Error creating spelling map.";
217	      return false;
218	    }
219	    auto i = script->begin();
220	    auto item = spelling_map->begin();
221	    for (; i != script->end(); ++i, ++item) {
222	      size_t list_size = i->second.size();
223	      item->size = list_size;
224	      item->at = Allocate<prism::SpellingDescriptor>(list_size);
225	      if (!item->at) {
226	        LOG(ERROR) << "Error creating spelling descriptors.";
227	        return false;
228	      }
229	      auto j = i->second.begin();
230	      auto desc = item->begin();
231	      for (; j != i->second.end(); ++j, ++desc) {
232	        desc->syllable_id = syllable_to_id[j->str];
233	        // 打包寫入 type + is_correction
234	        int32_t packed_type = static_cast<int32_t>(j->properties.type);
235	        if (j->properties.is_correction) {
236	          packed_type |= kTypeIsCorrectionMask;
237	        }
238	        desc->type = packed_type;
239	        desc->credibility = j->properties.credibility;
240	        if (!j->properties.tips.empty() &&
241	            !CopyString(j->properties.tips, &desc->tips)) {
242	          LOG(ERROR) << "Error creating spelling properties.";
243	          return false;
244	        }
245	      }
246	    }
247	    metadata->spelling_map = spelling_map;
248	    spelling_map_ = spelling_map;
249	  }
250	  // at last, complete the metadata
251	  std::strncpy(metadata->format, kPrismFormat,
252	               prism::Metadata::kFormatMaxLength);
253	  return true;
254	}
