270	// Given a key, search all the keys in the tree that share
271	// a common prefix with that key.
272	void Prism::CommonPrefixSearch(const string& key, vector<Match>* result) {
273	  if (!result || key.empty())
274	    return;
275	  size_t len = key.length();
276	  result->resize(len);
277	  size_t num_results =
278	      trie_->commonPrefixSearch(key.c_str(), &result->front(), len, len);
279	  result->resize(num_results);
280	}
281	
282	void Prism::ExpandSearch(const string& key,
283	                         vector<Match>* result,
284	                         size_t limit) {
285	  if (!result)
286	    return;
287	  result->clear();
288	  size_t count = 0;
289	  size_t node_pos = 0;
290	  size_t key_pos = 0;
291	  int ret = trie_->traverse(key.c_str(), node_pos, key_pos);
292	  // key is not a valid path
293	  if (ret == -2)
294	    return;
295	  if (ret != -1) {
296	    result->push_back(Match{ret, key_pos});
297	    if (limit && ++count >= limit)
298	      return;
299	  }
300	  std::queue<node_t> q;
301	  q.push({key, node_pos});
302	  while (!q.empty()) {
303	    node_t node = q.front();
304	    q.pop();
305	    const char* c =
306	        (format_ > 1.0 - DBL_EPSILON) ? metadata_->alphabet : kDefaultAlphabet;
307	    for (; *c; ++c) {
308	      string k = node.key + *c;
309	      size_t k_pos = node.key.length();
310	      size_t n_pos = node.node_pos;
311	      ret = trie_->traverse(k.c_str(), n_pos, k_pos);
312	      if (ret <= -2) {
313	        // ignore
314	      } else if (ret == -1) {
315	        q.push({k, n_pos});
316	      } else {
317	        q.push({k, n_pos});
318	        result->push_back(Match{ret, k_pos});
319	        if (limit && ++count >= limit)
320	          return;
321	      }
322	    }
323	  }
324	}
