138	inline static bool node_less(const table::TrunkIndexNode& a,
139	                             const table::TrunkIndexNode& b) {
140	  return a.key < b.key;
141	}
142	
143	static table::TrunkIndexNode* find_node(table::TrunkIndexNode* first,
144	                                        table::TrunkIndexNode* last,
145	                                        const SyllableId& key) {
146	  table::TrunkIndexNode target;
147	  target.key = key;
148	  auto it = std::lower_bound(first, last, target, node_less);
149	  return it == last || key < it->key ? last : it;
150	}
151	
152	bool TableQuery::Walk(SyllableId syllable_id) {
153	  if (level_ == 0) {
154	    if (!lv1_index_ || syllable_id < 0 ||
155	        syllable_id >= static_cast<SyllableId>(lv1_index_->size))
156	      return false;
157	    auto node = &lv1_index_->at[syllable_id];
158	    if (!node->next_level)
159	      return false;
160	    lv2_index_ = &node->next_level->trunk();
161	  } else if (level_ == 1) {
162	    if (!lv2_index_)
163	      return false;
164	    auto node = find_node(lv2_index_->begin(), lv2_index_->end(), syllable_id);
165	    if (node == lv2_index_->end())
166	      return false;
167	    if (!node->next_level)
168	      return false;
169	    lv3_index_ = &node->next_level->trunk();
170	  } else if (level_ == 2) {
171	    if (!lv3_index_)
172	      return false;
173	    auto node = find_node(lv3_index_->begin(), lv3_index_->end(), syllable_id);
174	    if (node == lv3_index_->end())
175	      return false;
176	    if (!node->next_level)
177	      return false;
178	    lv4_index_ = &node->next_level->tail();
179	  } else {
180	    return false;
181	  }
182	  return true;
183	}
