269	bool Table::Load() {
270	  LOG(INFO) << "loading table file: " << file_path();
271	
272	  if (IsOpen())
273	    Close();
274	
275	  if (!OpenReadOnly()) {
276	    LOG(ERROR) << "Error opening table file '" << file_path() << "'.";
277	    return false;
278	  }
279	
280	  metadata_ = Find<table::Metadata>(0);
281	  if (!metadata_) {
282	    LOG(ERROR) << "metadata not found.";
283	    Close();
284	    return false;
285	  }
286	  if (strncmp(metadata_->format, kTableFormatPrefix, kTableFormatPrefixLen)) {
287	    LOG(ERROR) << "invalid metadata.";
288	    Close();
289	    return false;
290	  }
291	  double format_version = atof(&metadata_->format[kTableFormatPrefixLen]);
292	  if (format_version < kTableFormatLowestCompatible - DBL_EPSILON) {
293	    LOG(ERROR) << "table format version " << format_version
294	               << " is no longer supported. please upgrade to version "
295	               << kTableFormatLatest;
296	    return false;
297	  }
298	
299	  syllabary_ = metadata_->syllabary.get();
300	  if (!syllabary_) {
301	    LOG(ERROR) << "syllabary not found.";
302	    Close();
303	    return false;
304	  }
305	  index_ = metadata_->index.get();
306	  if (!index_) {
307	    LOG(ERROR) << "table index not found.";
308	    Close();
309	    return false;
310	  }
311	
312	  return OnLoad();
313	}
