330	bool Table::Build(const Syllabary& syllabary,
331	                  const Vocabulary& vocabulary,
332	                  size_t num_entries,
333	                  uint32_t dict_file_checksum) {
334	  const size_t kReservedSize = 4096;
335	  size_t num_syllables = syllabary.size();
336	  size_t estimated_file_size =
337	      kReservedSize + 32 * num_syllables + 64 * num_entries;
338	  LOG(INFO) << "building table.";
339	  LOG(INFO) << "num syllables: " << num_syllables;
340	  LOG(INFO) << "num entries: " << num_entries;
341	  LOG(INFO) << "estimated file size: " << estimated_file_size;
342	  if (!Create(estimated_file_size)) {
343	    LOG(ERROR) << "Error creating table file '" << file_path() << "'.";
344	    return false;
345	  }
346	
347	  LOG(INFO) << "creating metadata.";
348	  metadata_ = Allocate<table::Metadata>();
349	  if (!metadata_) {
350	    LOG(ERROR) << "Error creating metadata in file '" << file_path() << "'.";
351	    return false;
352	  }
353	  metadata_->dict_file_checksum = dict_file_checksum;
354	  metadata_->num_syllables = num_syllables;
355	  metadata_->num_entries = num_entries;
356	
357	  if (!OnBuildStart()) {
358	    return false;
359	  }
360	
361	  LOG(INFO) << "creating syllabary.";
362	  syllabary_ = CreateArray<table::StringType>(num_syllables);
363	  if (!syllabary_) {
364	    LOG(ERROR) << "Error creating syllabary.";
365	    return false;
366	  } else {
367	    size_t i = 0;
368	    for (const string& syllable : syllabary) {
369	      AddString(syllable, &syllabary_->at[i++], 0.0);
370	    }
371	  }
372	  metadata_->syllabary = syllabary_;
373	
374	  LOG(INFO) << "creating table index.";
375	  index_ = BuildIndex(vocabulary, num_syllables);
376	  if (!index_) {
377	    LOG(ERROR) << "Error creating table index.";
378	    return false;
379	  }
380	  metadata_->index = index_;
381	
382	  if (!OnBuildFinish()) {
383	    return false;
384	  }
385	
386	  // at last, complete the metadata
387	  std::strncpy(metadata_->format, kTableFormatLatest,
388	               table::Metadata::kFormatMaxLength);
389	  return true;
390	}
