397	
398	table::HeadIndex* Table::BuildHeadIndex(const Vocabulary& vocabulary,
399	                                        size_t num_syllables) {
400	  auto index = CreateArray<table::HeadIndexNode>(num_syllables);
401	  if (!index) {
402	    return NULL;
403	  }
404	  for (const auto& v : vocabulary) {
405	    int syllable_id = v.first;
406	    auto& node(index->at[syllable_id]);
407	    const auto& entries(v.second.entries);
408	    if (!BuildEntryList(entries, &node.entries)) {
409	      return NULL;
410	    }
411	    if (v.second.next_level) {
412	      Code code;
413	      code.push_back(syllable_id);
414	      auto next_level_index = BuildTrunkIndex(code, *v.second.next_level);
415	      if (!next_level_index) {
416	        return NULL;
417	      }
418	      node.next_level = reinterpret_cast<table::PhraseIndex*>(next_level_index);
419	    }
420	  }
421	  return index;
422	}
423	
424	table::TrunkIndex* Table::BuildTrunkIndex(const Code& prefix,
425	                                          const Vocabulary& vocabulary) {
426	  auto index = CreateArray<table::TrunkIndexNode>(vocabulary.size());
427	  if (!index) {
428	    return NULL;
429	  }
430	  size_t count = 0;
431	  for (const auto& v : vocabulary) {
432	    int syllable_id = v.first;
433	    auto& node(index->at[count++]);
434	    node.key = syllable_id;
435	    const auto& entries(v.second.entries);
436	    if (!BuildEntryList(entries, &node.entries)) {
437	      return NULL;
438	    }
439	    if (v.second.next_level) {
440	      Code code(prefix);
441	      code.push_back(syllable_id);
442	      if (code.size() < Code::kIndexCodeMaxLength) {
443	        auto next_level_index = BuildTrunkIndex(code, *v.second.next_level);
444	        if (!next_level_index) {
445	          return NULL;
446	        }
447	        node.next_level =
448	            reinterpret_cast<table::PhraseIndex*>(next_level_index);
449	      } else {
450	        auto tail_index = BuildTailIndex(code, *v.second.next_level);
451	        if (!tail_index) {
452	          return NULL;
453	        }
454	        node.next_level = reinterpret_cast<table::PhraseIndex*>(tail_index);
455	      }
456	    }
457	  }
458	  return index;
459	}
460	
461	table::TailIndex* Table::BuildTailIndex(const Code& prefix,
462	                                        const Vocabulary& vocabulary) {
463	  if (vocabulary.find(-1) == vocabulary.end()) {
464	    return NULL;
465	  }
466	  const auto& page(vocabulary.find(-1)->second);
467	  DLOG(INFO) << "page size: " << page.entries.size();
468	  auto index = CreateArray<table::LongEntry>(page.entries.size());
469	  if (!index) {
470	    return NULL;
471	  }
472	  size_t count = 0;
473	  for (const auto& src : page.entries) {
474	    DLOG(INFO) << "count: " << count;
475	    DLOG(INFO) << "entry: " << src->text;
476	    auto& dest(index->at[count++]);
477	    size_t extra_code_length = src->code.size() - Code::kIndexCodeMaxLength;
478	    DLOG(INFO) << "extra code length: " << extra_code_length;
479	    dest.extra_code.size = extra_code_length;
480	    dest.extra_code.at = Allocate<SyllableId>(extra_code_length);
481	    if (!dest.extra_code.at) {
482	      LOG(ERROR) << "Error creating code sequence; file size: " << file_size();
483	      return NULL;
484	    }
485	    std::copy(src->code.begin() + Code::kIndexCodeMaxLength, src->code.end(),
486	              dest.extra_code.begin());
487	    BuildEntry(*src, &dest.entry);
488	  }
489	  return index;
490	}
