568	// log(0.05) ≈ -3.0
569	const double kPenaltyForAmbiguousSyllable = -2.995732274;
570	
571	bool Table::Query(const SyllableGraph& syll_graph,
572	                  size_t start_pos,
573	                  TableQueryResult* result) {
574	  if (!result || !index_ || start_pos >= syll_graph.interpreted_length)
575	    return false;
576	  result->clear();
577	  std::queue<pair<size_t, TableQuery>> q;
578	  TableQuery initial_state(index_);
579	  q.push({start_pos, initial_state});
580	  while (!q.empty()) {
581	    size_t current_pos = q.front().first;
582	    TableQuery query(q.front().second);
583	    q.pop();
584	    auto index = syll_graph.indices.find(current_pos);
585	    if (index == syll_graph.indices.end()) {
586	      continue;
587	    }
588	    if (query.level() == Code::kIndexCodeMaxLength) {
589	      TableAccessor accessor(query.Access(-1));
590	      if (!accessor.exhausted()) {
591	        (*result)[current_pos].push_back(accessor);
592	      }
593	      continue;
594	    }
595	    for (const auto& spellings : index->second) {
596	      SyllableId syll_id = spellings.first;
597	      for (auto props : spellings.second) {
598	        size_t end_pos = props->end_pos;
599	
600	        double penalty = 0.0;
601	        if (false) {
602	          size_t last_pos = query.last_pos();
603	          if (props->ambiguous_source_positions.count(last_pos)) {
604	            penalty = kPenaltyForAmbiguousSyllable;
605	            DLOG(INFO) << "conditional penalty applied: ambiguous path ["
606	                       << last_pos << ", " << end_pos << ")";
607	          }
608	        }
609	        double next_credibility = props->credibility + penalty;
610	
611	        // 全碼匹配長度積分
612	        bool is_normal_spelling = props->type == kNormalSpelling;
613	        double delta_quality_len =
614	            (is_normal_spelling ? 1.0 : 0.0) * (end_pos - current_pos);
615	        TableAccessor accessor =
616	            query.Access(syll_id, next_credibility, delta_quality_len);
617	        if (!accessor.exhausted()) {
618	          (*result)[end_pos].push_back(accessor);
619	        }
620	        if (end_pos < syll_graph.interpreted_length &&
621	            query.Advance(syll_id, next_credibility, delta_quality_len,
622	                          current_pos)) {
623	          q.push({end_pos, query});
624	          query.Backdate();
625	        }
626	      }
627	    }
628	  }
629	  return !result->empty();
630	}
