27	struct DfsState {
28	  size_t depth_limit;
29	  size_t predict_word_from_depth;
30	  TickCount present_tick;
31	  Code code;
32	  vector<double> credibility;
33	  vector<double> quality_len;
34	  hash_map<int, DictEntryList> query_result;
35	  an<DbAccessor> accessor;
36	  string key;
37	  string value;
38	
39	  size_t depth() const { return code.size(); }
40	
41	  bool IsExactMatch(const string& prefix) {
42	    return boost::starts_with(key, prefix + '\t');
43	  }
44	  bool IsPrefixMatch(const string& prefix) {
45	    return boost::starts_with(key, prefix);
46	  }
47	  void RecruitEntry(size_t pos,
48	                    hash_map<string, SyllableId>* syllabary = nullptr);
49	  bool NextEntry() {
50	    if (!accessor->GetNextRecord(&key, &value)) {
51	      key.clear();
52	      value.clear();
53	      return false;  // reached the end
54	    }
55	    return true;
56	  }
57	  bool ForwardScan(const string& prefix) {
58	    if (!accessor->Jump(prefix)) {
59	      return false;
60	    }
61	    return NextEntry();
62	  }
63	  bool Backdate(const string& prefix) {
64	    DLOG(INFO) << "backdate; prefix: " << prefix;
65	    if (!accessor->Reset()) {
66	      LOG(WARNING) << "backdating failed for '" << prefix << "'.";
67	      return false;
68	    }
69	    return NextEntry();
70	  }
71	};
72	
73	void DfsState::RecruitEntry(size_t pos,
74	                            hash_map<string, SyllableId>* syllabary) {
75	  string full_code;
76	  auto e = UserDictionary::CreateDictEntry(
77	      key, value, present_tick, credibility.back(), quality_len.back(),
78	      syllabary ? &full_code : nullptr);
79	  if (e) {
80	    if (syllabary) {
81	      vector<string> syllables =
82	          strings::split(full_code, " ", strings::SplitBehavior::SkipToken);
83	      Code numeric_code;
84	      for (auto s = syllables.begin(); s != syllables.end(); ++s) {
85	        auto found = syllabary->find(*s);
86	        if (found == syllabary->end()) {
87	          LOG(ERROR) << "failed to recruit dict entry '" << e->text
88	                     << "', unrecognized syllable: " << *s;
89	          return;
90	        }
91	        numeric_code.push_back(found->second);
92	      }
93	      e->code = numeric_code;
94	      e->matching_code_size = code.size();
95	    } else {
96	      e->code = code;
97	    }
98	    DLOG(INFO) << "add entry at pos " << pos;
99	    query_result[pos].push_back(e);
100	  }
101	}
