193	// this is a one-pass scan for the user db which supports sequential access
194	// in alphabetical order (of syllables).
195	// each call to DfsLookup() searches for matching phrases at a given
196	// start position: current_pos.
197	// there may be multiple edges that start at current_pos, and ends at different
198	// positions after current_pos. on each edge, there can be multiple syllables
199	// the spelling on the edge maps to.
200	// in order to enable forward scanning and to avoid backdating, our strategy is:
201	// sort all those syllables from edges that starts at current_pos, so that
202	// the syllables are in the same alphabetical order as the user db's.
203	// this having been done by transposing the syllable graph into
204	// SyllableGraph::index.
205	// however, in the case of 'shsh' which could be the abbreviation of either
206	// 'sh(a) sh(i)' or 'sh(a) s(hi) h(ou)',
207	// we now have to give up the latter path in order to avoid backdating.
208	
209	// update: 2013-06-25
210	// to fix the following issue, we have to reintroduce backdating in db scan:
211	// given aaa=A, b=B, ab=C, derive/^(aa)a$/$1/,
212	// the input 'aaab' can be either aaa'b=AB or aa'ab=AC.
213	// note that backdating works only for normal or fuzzy spellings, but not for
214	// abbreviations such as 'shsh' in the previous example.
215	
216	void UserDictionary::DfsLookup(const SyllableGraph& syll_graph,
217	                               size_t current_pos,
218	                               const string& current_prefix,
219	                               DfsState* state) {
220	  auto index = syll_graph.indices.find(current_pos);
221	  if (index == syll_graph.indices.end()) {
222	    return;
223	  }
224	  DLOG(INFO) << "dfs lookup starts from " << current_pos;
225	  string prefix;
226	  for (const auto& spelling : index->second) {
227	    DLOG(INFO) << "prefix: '" << current_prefix << "'"
228	               << ", syll_id: " << spelling.first
229	               << ", num_spellings: " << spelling.second.size();
230	    state->code.push_back(spelling.first);
231	    BOOST_SCOPE_EXIT((&state)) {
232	      state->code.pop_back();
233	    }
234	    BOOST_SCOPE_EXIT_END
235	    if (!TranslateCodeToString(state->code, &prefix))
236	      continue;
237	    for (size_t i = 0; i < spelling.second.size(); ++i) {
238	      auto props = spelling.second[i];
239	      if (i > 0 && props->type >= kAbbreviation)
240	        continue;
241	      state->credibility.push_back(state->credibility.back() +
242	                                   props->credibility);
243	      size_t end_pos = props->end_pos;
244	      // 全碼匹配長度積分
245	      bool is_normal_spelling = props->type == kNormalSpelling;
246	      double delta_quality_len =
247	          (is_normal_spelling ? 1.0 : 0.0) * (end_pos - current_pos);
248	      state->quality_len.push_back(state->quality_len.back() +
249	                                   delta_quality_len);
250	      BOOST_SCOPE_EXIT((&state)) {
251	        state->credibility.pop_back();
252	        state->quality_len.pop_back();
253	      }
254	      BOOST_SCOPE_EXIT_END
255	      DLOG(INFO) << "edge: [" << current_pos << ", " << end_pos << ")";
256	      if (prefix != state->key) {  // 'a b c |d ' > 'a b c \tabracadabra'
257	        DLOG(INFO) << "forward scanning for '" << prefix << "'.";
258	        if (!state->ForwardScan(prefix))  // reached the end of db
259	          continue;
260	      }
261	      while (state->IsExactMatch(prefix)) {  // 'b |e ' vs. 'b e \tBe'
262	        DLOG(INFO) << "match found for '" << prefix << "'.";
263	        state->RecruitEntry(end_pos);
264	        if (!state->NextEntry())  // reached the end of db
265	          break;
266	      }
267	      auto next_index = syll_graph.indices.find(end_pos);
268	      if (next_index == syll_graph.indices.end()) {
269	        // reached the end of input, predict word if requested
270	        if (state->predict_word_from_depth != 0 &&
271	            state->depth() >= state->predict_word_from_depth) {
272	          while (state->IsPrefixMatch(prefix)) {
273	            DLOG(INFO) << "prefix match found for '" << prefix << "'.";
274	            if (syllabary_.empty()) {
275	              Syllabary syllabary;
276	              if (!table_->GetSyllabary(&syllabary)) {
277	                LOG(ERROR) << "failed to get syllabary for user dict: "
278	                           << name();
279	                break;
280	              }
281	              SyllableId syllable_id = 0;
282	              for (auto s = syllabary.begin(); s != syllabary.end(); ++s) {
283	                syllabary_[*s] = syllable_id++;
284	              }
285	            }
286	            state->RecruitEntry(end_pos, &syllabary_);
287	            if (!state->NextEntry())  // reached the end of db
288	              break;
289	          }
290	        }
291	      } else {
292	        // the caller can limit the number of syllables to look up
293	        if ((!state->depth_limit || state->depth() < state->depth_limit) &&
294	            state->IsPrefixMatch(prefix)) {  // 'b |e ' vs. 'b e f \tBefore'
295	          DfsLookup(syll_graph, end_pos, prefix, state);
296	        }
297	      }
298	    }
299	    if (!state->IsPrefixMatch(current_prefix))  // 'b |' vs. 'g o \tGo'
300	      return;
301	    // 'b |e ' vs. 'b y \tBy'
302	  }
303	}
