425	bool UserDictionary::UpdateEntry(const DictEntry& entry,
426	                                 int commits,
427	                                 const string& new_entry_prefix) {
428	  string code_str(entry.custom_code);
429	  if (code_str.empty() && !TranslateCodeToString(entry.code, &code_str))
430	    return false;
431	  string key(code_str + '\t' + entry.text);
432	  string value;
433	  UserDbValue v;
434	  if (db_->Fetch(key, &value)) {
435	    v.Unpack(value);
436	    if (v.tick > tick_) {
437	      v.tick = tick_;  // fix abnormal timestamp
438	    }
439	  } else if (!new_entry_prefix.empty()) {
440	    key.insert(0, new_entry_prefix);
441	  }
442	  if (commits > 0) {
443	    if (v.commits < 0)
444	      v.commits = -v.commits;  // revive a deleted item
445	    v.commits += commits;
446	    UpdateTickCount(1);
447	    v.dee = algo::formula_d(commits, (double)tick_, v.dee, (double)v.tick);
448	  } else if (commits == 0) {
449	    const double k = 0.1;
450	    v.dee = algo::formula_d(k, (double)tick_, v.dee, (double)v.tick);
451	  } else if (commits < 0) {  // mark as deleted
452	    v.commits = (std::min)(-1, -v.commits);
453	    v.dee = algo::formula_d(0.0, (double)tick_, v.dee, (double)v.tick);
454	  }
455	  v.tick = tick_;
456	  return db_->Update(key, v.Pack());
457	}
