512	bool UserDictionary::TranslateCodeToString(const Code& code, string* result) {
513	  if (!table_ || !result)
514	    return false;
515	  result->clear();
516	  for (const SyllableId& syllable_id : code) {
517	    string spelling = rev_syllabary_.count(syllable_id)
518	                          ? rev_syllabary_[syllable_id]
519	                          : (rev_syllabary_[syllable_id] =
520	                                 table_->GetSyllableById(syllable_id));
521	    if (spelling.empty()) {
522	      LOG(ERROR) << "Error translating syllable_id '" << syllable_id << "'.";
523	      result->clear();
524	      return false;
525	    }
526	    *result += spelling;
527	    *result += ' ';
528	  }
529	  return true;
530	}
531	
532	an<DictEntry> UserDictionary::CreateDictEntry(const string& key,
533	                                              const string& value,
534	                                              TickCount present_tick,
535	                                              double credibility,
536	                                              double quality_len,
537	                                              string* full_code) {
538	  an<DictEntry> e;
539	  size_t separator_pos = key.find('\t');
540	  if (separator_pos == string::npos)
541	    return e;
542	  UserDbValue v;
543	  if (!v.Unpack(value))
544	    return e;
545	  if (v.commits < 0)  // deleted entry
546	    return e;
547	  if (v.tick < present_tick)
548	    v.dee = algo::formula_d(0, (double)present_tick, v.dee, (double)v.tick);
549	  // create!
550	  e = New<DictEntry>();
551	  e->text = key.substr(separator_pos + 1);
552	  e->commit_count = v.commits;
553	  // TODO: argument s not defined...
554	  double weight = algo::formula_p(0, (double)v.commits / present_tick,
555	                                  (double)present_tick, v.dee);
556	  e->weight = log(weight > 0 ? weight : DBL_EPSILON) + credibility;
557	  e->quality_len = quality_len;
558	  if (full_code) {
559	    *full_code = key.substr(0, separator_pos);
560	  }
561	  DLOG(INFO) << "text = '" << e->text << "', code_len = " << e->code.size()
562	             << ", weight = " << e->weight
563	             << ", quality_len = " << e->quality_len
564	             << ", commit_count = " << e->commit_count
565	             << ", present_tick = " << present_tick;
566	  return e;
567	}
