591	  Config* config = ticket.schema->config();
592	  bool enable_user_dict = true;
593	  config->GetBool(ticket.name_space + "/enable_user_dict", &enable_user_dict);
594	  if (!enable_user_dict)
595	    return NULL;
596	  string dict_name;
597	  if (config->GetString(ticket.name_space + "/user_dict", &dict_name)) {
598	    // user specified name
599	  } else if (config->GetString(ticket.name_space + "/dictionary", &dict_name)) {
600	    // {dictionary: luna_pinyin.extra} implies {user_dict: luna_pinyin}
601	    dict_name = Language::get_language_component(dict_name);
602	  } else {
603	    LOG(ERROR) << ticket.name_space << "/dictionary not specified in schema '"
604	               << ticket.schema->schema_id() << "'.";
605	    return NULL;
606	  }
607	  string db_class("userdb");
608	  if (config->GetString(ticket.name_space + "/db_class", &db_class)) {
609	    // user specified db class
610	  }
611	  // obtain userdb object
612	  return Create(dict_name, db_class);
613	}
