249	  out << "# syllabary:" << std::endl;
250	  for (const string& syllable : syllabary) {
251	    out << "# - " << syllable << std::endl;
252	  }
253	  out << std::endl;
254	  for (const auto& e : entries) {
255	    out << e->text << '\t' << e->raw_code.ToString() << '\t' << e->weight
256	        << std::endl;
257	  }
258	  out.close();
